		if p ~= nil then
			if p:getBeamWeaponRange(0) > 0 then
				local beam_index = 0
				repeat
					p:setBeamWeaponEnergyPerFire(beam_index,p:getBeamWeaponEnergyPerFire(beam_index)*.9)
					beam_index = beam_index + 1
