		end
		planetAddSize()
	end)
	addGMFunction(string.format("v1U from %sU",add_planet_size/1000),function()
		if add_planet_size - 1000 < 1000 then
			addGMMessage("Minimum size: 1U. No action taken")
		else
			add_planet_size = add_planet_size - 1000
		end
		planetAddSize()
	end)
end
