						end
						addCommsReply(string.format("Back to %s",calling_function.name),calling_function.identifier)
						addCommsReply("Back to station communication", commsStation)
					end)
				end
				addCommsReply(string.format("Back to %s",calling_function.name),calling_function.identifier)
				addCommsReply("Back to station communication", commsStation)
			end)
			addCommsReply(string.format("Back to %s",calling_function.name),calling_function.identifier)
			addCommsReply("Back to station communication", commsStation)
		end)
	end)
end
