function movingObjects(delta)
	if icarus_mobile_nebula_1 ~= nil and icarus_mobile_nebula_1:isValid() then
		local neb_x, neb_y = icarus_mobile_nebula_1:getPosition()
		if neb_x < -10000 then
			neb_x = -10000
		    icarus_mobile_nebula_1.increment = random(0,10)
			if neb_y > 110000 then
				--icarus_mobile_nebula_1.angle = random(1,89)
				icarus_mobile_nebula_1.angle = random(271,359)
			else
				--icarus_mobile_nebula_1.angle = random(91,179)
				icarus_mobile_nebula_1.angle = random(1,89)
			end
		end
		if neb_x > 80000 then
			neb_x = 80000
		    icarus_mobile_nebula_1.increment = random(0,10)
			if neb_y > 110000 then
				--icarus_mobile_nebula_1.angle = random(271,359)
				icarus_mobile_nebula_1.angle = random(181,269)
			else
				--icarus_mobile_nebula_1.angle = random(181,269)
				icarus_mobile_nebula_1.angle = random(91,179)
			end
		end
		if neb_y < 80000 then
			neb_y = 80000
		    icarus_mobile_nebula_1.increment = random(0,10)
			if neb_x > 45000 then
				--icarus_mobile_nebula_1.angle = random(181,269)
				icarus_mobile_nebula_1.angle = random(91,179)
			else
				--icarus_mobile_nebula_1.angle = random(91,179)
				icarus_mobile_nebula_1.angle = random(1,89)
			end
		end
		if neb_y > 140000 then
			neb_y = 140000
		    icarus_mobile_nebula_1.increment = random(0,10)
			if neb_x > 45000 then
				--icarus_mobile_nebula_1.angle = random(271,359)
				icarus_mobile_nebula_1.angle = random(181,269)
			else
				--icarus_mobile_nebula_1.angle = random(1,89)
				icarus_mobile_nebula_1.angle = random(271,359)
			end
		end
		local dx, dy = vectorFromAngle(icarus_mobile_nebula_1.angle,icarus_mobile_nebula_1.increment)
		icarus_mobile_nebula_1:setPosition(neb_x+dx,neb_y+dy)
		local nr = icarus_mobile_nebula_1:getRotation()
		nr = nr + .01
		if nr > 360 then 
			nr = nr - 360
		end
		icarus_mobile_nebula_1:setRotation(nr)
	end
	if kentar_mobile_nebula_1 ~= nil and kentar_mobile_nebula_1:isValid() then
		if kentar_mobile_nebula_1.lower_black_hole then
			--print(string.format("Lower start angle: %f, ready: %s",kentar_mobile_nebula_1.angle,tostring(kentar_mobile_nebula_1.ready)))
			kentar_mobile_nebula_1.angle = kentar_mobile_nebula_1.angle + kentar_mobile_nebula_1.increment
			if kentar_mobile_nebula_1.angle > 360 then
				kentar_mobile_nebula_1.angle = kentar_mobile_nebula_1.angle - 360
			end
			--print(string.format("Lower mod 1 angle: %f, ready: %s",kentar_mobile_nebula_1.angle,tostring(kentar_mobile_nebula_1.ready)))
			if kentar_mobile_nebula_1.ready then
				if kentar_mobile_nebula_1.angle >= 315 then
					--switch
					kentar_mobile_nebula_1.lower_black_hole = false
					kentar_mobile_nebula_1.angle = 135 - (kentar_mobile_nebula_1.angle - 315)
					kentar_mobile_nebula_1.center_x = 290000
					kentar_mobile_nebula_1.center_y = 210000
					kentar_mobile_nebula_1.ready = false
				end
			else
				if kentar_mobile_nebula_1.angle < 315 then
					kentar_mobile_nebula_1.ready = true
				end
			end
			--print(string.format("Lower mod 2 angle: %f, ready: %s",kentar_mobile_nebula_1.angle,tostring(kentar_mobile_nebula_1.ready)))
		else
			--print(string.format("Upper start angle: %f, ready: %s",kentar_mobile_nebula_1.angle,tostring(kentar_mobile_nebula_1.ready)))
			kentar_mobile_nebula_1.angle = kentar_mobile_nebula_1.angle - kentar_mobile_nebula_1.increment
			if kentar_mobile_nebula_1.angle < 0 then
				kentar_mobile_nebula_1.angle = kentar_mobile_nebula_1.angle + 360
			end
			--print(string.format("Upper mod 1 angle: %f, ready: %s",kentar_mobile_nebula_1.angle,tostring(kentar_mobile_nebula_1.ready)))
			if kentar_mobile_nebula_1.ready then
				if kentar_mobile_nebula_1.angle <= 135 then
					--switch
					kentar_mobile_nebula_1.lower_black_hole = true
					kentar_mobile_nebula_1.angle = 315 + (135 - kentar_mobile_nebula_1.angle)
					kentar_mobile_nebula_1.center_x = 210000
					kentar_mobile_nebula_1.center_y = 290000
					kentar_mobile_nebula_1.ready = false
				end
			else
				if kentar_mobile_nebula_1.angle > 135 then
					kentar_mobile_nebula_1.ready = true
				end
			end
			--print(string.format("Upper mod 2 angle: %f, ready: %s",kentar_mobile_nebula_1.angle,tostring(kentar_mobile_nebula_1.ready)))
		end
		local px,py = vectorFromAngle(kentar_mobile_nebula_1.angle,kentar_mobile_nebula_1.mobile_neb_dist)
		kentar_mobile_nebula_1:setPosition(kentar_mobile_nebula_1.center_x+px,kentar_mobile_nebula_1.center_y+py)
	end
	if planet_grendel ~= nil and planet_grendel:isValid() then
		if goodall_package_players ~= nil and #goodall_package_players > 0 then
			for i,p in ipairs(goodall_package_players) do
				if p ~= nil and p:isValid() then
					if stationGoodall:isValid() then
						if distance(p,stationGoodall) > 500000 then
							if p:hasJumpDrive() then
								p.max_jump_range = p.goodall_previous_max_jump_range
								p.min_jump_range = p.goodall_previous_min_jump_range
								p:setJumpDriveRange(p.min_jump_range,p.max_jump_range)
								p.goodall_previous_max_jump_range = nil
								p.goodall_previous_min_jump_range = nil
							end
							if p:hasWarpDrive() then
								p:setWarpSpeed(p.goodall_previous_warp_speed)
								p.goodall_previous_warp_speed = nil
							end
							p.normal_long_range_radar = p.goodall_previous_long_range_radar
							p.goodall_previous_long_range_radar = nil
							p:setLongRangeRadarRange(p.normal_long_range_radar)
							p.goodall_package = false
							goodall_package_players[i] = goodall_package_players[#goodall_package_players]
							goodall_package_players[#goodall_package_players] = nil
							break
						end
					else
						if p:hasJumpDrive() then
							p.max_jump_range = p.goodall_previous_max_jump_range
							p.min_jump_range = p.goodall_previous_min_jump_range
							p:setJumpDriveRange(p.min_jump_range,p.max_jump_range)
							p.goodall_previous_max_jump_range = nil
							p.goodall_previous_min_jump_range = nil
						end
						if p:hasWarpDrive() then
							p:setWarpSpeed(p.goodall_previous_warp_speed)
							p.goodall_previous_warp_speed = nil
						end
						p.normal_long_range_radar = p.goodall_previous_long_range_radar
						p.goodall_previous_long_range_radar = nil
						p:setLongRangeRadarRange(p.normal_long_range_radar)
						p.goodall_package = false
						goodall_package_players[i] = goodall_package_players[#goodall_package_players]
						goodall_package_players[#goodall_package_players] = nil
						break
					end
				else
					goodall_package_players[i] = goodall_package_players[#goodall_package_players]
					goodall_package_players[#goodall_package_players] = nil
					break
				end
			end
		end
		if planet_grendel.upper_orbit then
			planet_grendel.angle = (planet_grendel.angle - planet_grendel.increment) % 360
			if planet_grendel.ready then
				if planet_grendel.angle <= 170 then
					planet_grendel.upper_orbit = false
					planet_grendel.angle = 350 + (170 - planet_grendel.angle)
					local geats_x, geats_y = star_geats:getPosition()
					planet_grendel.center_x = geats_x
					planet_grendel.center_y = geats_y
					planet_grendel.ready = false
				end
			else
				if planet_grendel.angle >= 350 then
					planet_grendel.ready = true
				end
			end
		else
			planet_grendel.angle = (planet_grendel.angle + planet_grendel.increment) % 360
			if planet_grendel.ready then
				if planet_grendel.angle >= 350 then
					planet_grendel.upper_orbit = true
					planet_grendel.angle = 170 - (planet_grendel.angle - 350)
					local heorot_x, heorot_y = star_heorot:getPosition()
					planet_grendel.center_x = heorot_x
					planet_grendel.center_y = heorot_y
					planet_grendel.ready = false
				end
			else
				if planet_grendel.angle > 170 and planet_grendel.angle < 350 then
					planet_grendel.ready = true
				end
			end
		end
		local px, py = vectorFromAngle(planet_grendel.angle,planet_grendel.orbit_distance,true)
		planet_grendel:setPosition(planet_grendel.center_x + px,planet_grendel.center_y + py)
		if goodall_planets ~= nil then
			for i,obj in ipairs(goodall_planets) do
				if isObjectType(obj,"Nebula") then
					if obj.center_x ~= nil then
						obj.angle = (obj.angle + obj.increment) % 360
						px, py = vectorFromAngle(obj.angle,planet_grendel.orbit_distance*1.2,true)
						obj:setPosition(obj.center_x + px, obj.center_y + py)
					end
				end
				if isObjectType(obj,"CpuShip") then
					if obj:isValid() then
						if obj.patrol_info ~= nil then
							local obj_x, obj_y = obj:getPosition()
							local angle = obj.patrol_info[obj.patrol_info_index].angle
							local move_x, move_y = vectorFromAngle(angle,2,true)
	--						print(obj:getCallSign(),"angle:",angle,"move:",move_x,move_y)
							obj:setPosition(obj_x + move_x, obj_y + move_y)
							obj.patrol_info_count = obj.patrol_info_count + 1
							if obj.patrol_info_count > 2500 then
								obj.patrol_info_count = 0
								obj.patrol_info_index = obj.patrol_info_index + 1
								if obj.patrol_info_index > #obj.patrol_info then
									obj.patrol_info_index = 1
								end
							end
						end
						if obj.angle ~= nil then
							obj.angle = (obj.angle - obj.increment) % 360
							px, py = vectorFromAngle(obj.angle,4000,true)
							px = px + obj.center_x
							py = py + obj.center_y
							obj:setPosition(px, py)
						end
					end
				end
				if isObjectType(obj,"BlackHole") then
					if obj.joker_angle ~= nil then
						if obj.joker_orbit_updated then
							obj.joker_orbit_updated = false
							obj.joker_twin.joker_orbit_updated = false
						else
							obj.joker_angle = (obj.joker_angle + obj.joker_increment) % 360
							px, py = vectorFromAngle(obj.joker_angle,12000,true)
							obj:setPosition(obj.center_x + px, obj.center_y + py)
							obj.joker_twin.joker_angle = (obj.joker_twin.joker_angle + obj.joker_twin.joker_increment) % 360
							px, py = vectorFromAngle(obj.joker_twin.joker_angle,12000,true)
							obj.joker_twin:setPosition(obj.joker_twin.center_x + px, obj.joker_twin.center_y + py)
							obj.joker_orbit_updated = true
							obj.joker_twin.joker_orbit_updated = true
							if obj.increment_time == nil then
								local increment_time = getScenarioTime() + 1
								obj.increment_time = increment_time
								obj.joker_twin.increment_time = increment_time
							end
							if getScenarioTime() > obj.increment_time then
								obj.increment_time = nil
								obj.joker_twin.increment_time = nil
								if obj.accelerate then
									obj.joker_increment = obj.joker_increment + .01
									obj.joker_twin.joker_increment = obj.joker_twin.joker_increment + .01
									if obj.joker_increment > obj.joker_increment_max then
										obj.accelerate = false
										obj.joker_twin.accelerate = false
									end
								else
									obj.joker_increment = obj.joker_increment - .01
									obj.joker_twin.joker_increment = obj.joker_twin.joker_increment - .01
									if obj.joker_increment < obj.joker_increment_min then
										obj.accelerate = true
										obj.joker_twin.accelerate = true
									end
								end
							end
						end
					end
				end
			end
		end
	end
	if rotate_station ~= nil and #rotate_station > 0 then
		for i=1,#rotate_station do
			local current_station = rotate_station[i]
			if current_station ~= nil and current_station:isValid() then
				current_station:setRotation(current_station:getRotation()+.1)
				if current_station:getRotation() >= 360 then
					current_station:setRotation(0)
				end
			end
		end
	end
end
function triggerEpjam(p)
	string.format("")
	p:commandSetShieldFrequency(math.random(0,20))	
	local tube_size = {"small","medium","large"}
	EMPMissile():setPosition(p:getPosition()):setLifetime(0):setMissileSize(tube_size[p.epjam])
	p.epjam_recharge = getScenarioTime() + 60
	p:removeCustom(p.epjam_button_wea)
	p:removeCustom(p.epjam_button_tac)
end
