function activePlayerShips()
	local return_list = ""
	local players = getActivePlayerShips()
	for pidx, ship in ipairs(players) do
		if ship ~= nil and ship:isValid() then
			return_list = return_list .. ship:getCallSign()
		end
		return_list = return_list .. "\n"
	end
	return return_list
end
